import{_ as a,c as t,o as r,ae as o}from"./chunks/framework.4iBEZRE5.js";const p=JSON.parse('{"title":"NoteGen","description":"","frontmatter":{},"headers":[],"relativePath":"ja/guide.md","filePath":"ja/guide.md"}'),i={name:"ja/guide.md"};function l(n,e,s,d,h,c){return r(),t("div",null,e[0]||(e[0]=[o('<h1 id="notegen" tabindex="-1">NoteGen <a class="header-anchor" href="#notegen" aria-label="Permalink to &quot;NoteGen&quot;">​</a></h1><p>NoteGenは、AIを使用して記録と執筆を橋渡しし、断片化された知識を読みやすいノートに整理することに専念するクロスプラットフォームの<code>Markdown</code>ノートアプリケーションです。</p><h2 id="なぜnotegenを選ぶのか" tabindex="-1">なぜNoteGenを選ぶのか？ <a class="header-anchor" href="#なぜnotegenを選ぶのか" aria-label="Permalink to &quot;なぜNoteGenを選ぶのか？&quot;">​</a></h2><ul><li>軽量：<a href="https://github.com/codexu/note-gen/releases" target="_blank" rel="noreferrer">インストールパッケージ</a>は<strong>わずか約10MB</strong>、無料で広告やバンドルソフトウェアはありません。</li><li>クロスプラットフォーム：Mac、Windows、Linuxをサポートし、<code>Tauri2</code>のクロスプラットフォーム機能のおかげで、将来的にはiOSとAndroidもサポートします。</li><li><code>スクリーンショット</code>、<code>テキスト</code>、<code>イラスト</code>、<code>ファイル</code>、<code>リンク</code>など、さまざまな記録方法をサポートし、さまざまなシナリオでの断片化された記録ニーズに対応します。</li><li>ネイティブのオフライン使用をサポートし、<code>Markdown(.md)</code>をストレージ形式として使用し、<code>プライベートGitHubリポジトリ</code>へのリアルタイム同期と履歴のロールバックもサポートします。</li><li>AI強化：ChatGPT、Gemini、Ollama、LM Studio、DeepSeekなどのモデルを設定可能で、サードパーティのモデル設定もサポートします。</li></ul><h2 id="スクリーンショット" tabindex="-1">スクリーンショット <a class="header-anchor" href="#スクリーンショット" aria-label="Permalink to &quot;スクリーンショット&quot;">​</a></h2><p>記録：</p><p><img src="https://s2.loli.net/2025/04/14/NxhiWjMZT7RtusS.png" alt="record"></p><p>執筆：</p><p><img src="https://s2.loli.net/2025/04/16/LcgMvUa86IpRi4V.png" alt="writing"></p><p>ダークモード：</p><p><img src="https://s2.loli.net/2025/04/14/9JhgTie2X4tZLdz.png" alt="dark"></p><h2 id="記録から執筆へ" tabindex="-1">記録から執筆へ <a class="header-anchor" href="#記録から執筆へ" aria-label="Permalink to &quot;記録から執筆へ&quot;">​</a></h2><p>従来のノートアプリケーションは通常、記録機能を提供しません。ユーザーは手動でコンテンツをコピーして貼り付ける必要があり、記録の効率が大幅に低下します。断片化された記録コンテンツに直面すると、整理に多大な労力が必要です。</p><p>NoteGenは<code>記録</code>と<code>執筆</code>のページに分かれており、次の関係があります：</p><ul><li>記録はノートに整理され、執筆ページに転送されて詳細な執筆が行われます。</li><li>執筆中はいつでも記録を挿入できます。</li></ul><h3 id="記録" tabindex="-1">記録 <a class="header-anchor" href="#記録" aria-label="Permalink to &quot;記録&quot;">​</a></h3><p>記録機能は<strong>AIチャットボット</strong>に似ていますが、対話中に以前に記録したコンテンツと関連付けることができ、対話モードから整理モードに切り替えて、記録を読みやすいノートに整理できます。</p><p>次の補助機能は、より効果的に記録するのに役立ちます：</p><ul><li><strong>タグ</strong>：さまざまな記録シナリオを区別するため。</li><li><strong>ペルソナ</strong>：カスタムプロンプトをサポートし、AIアシスタントを正確に制御します。</li><li><strong>クリップボードアシスタント</strong>：クリップボード内のテキストや画像を自動的に認識し、リストに記録します。</li></ul><h3 id="執筆" tabindex="-1">執筆 <a class="header-anchor" href="#執筆" aria-label="Permalink to &quot;執筆&quot;">​</a></h3><p>執筆セクションは、<strong>ファイルマネージャー</strong>と<strong>Markdownエディター</strong>の2つの部分に分かれています。</p><p><strong>ファイルマネージャー</strong></p><ul><li>ローカルMarkdownファイルとGitHub同期ファイルの管理をサポートします。</li><li>無制限のディレクトリ階層をサポートします。</li><li>複数のソート方法をサポートします。</li></ul><p><strong>Markdownエディター</strong></p><ul><li>WYSIWYG、即時レンダリング、分割画面プレビューモードをサポートします。</li><li>バージョン管理をサポートし、履歴のロールバックが可能です。</li><li>会話、継続、ポリッシュ、翻訳機能のためのAI支援をサポートします。</li><li>画像ホスティングをサポートし、画像をアップロードしてMarkdown画像リンクに変換します。</li><li>HTMLからMarkdownへの変換をサポートし、コピーされたブラウザコンテンツを自動的にMarkdown形式に変換します。</li><li>アウトライン、数式、マインドマップ、チャート、フローチャート、ガントチャート、シーケンス図、五線譜、マルチメディア、音声読み上げ、タイトルアンカー、コードハイライトとコピー、graphvizレンダリング、plantuml UML図をサポートします。</li><li>リアルタイムのローカルコンテンツ保存、遅延（10秒間編集されていない場合）自動同期、履歴のロールバックをサポートします。</li></ul><h2 id="その他の機能" tabindex="-1">その他の機能 <a class="header-anchor" href="#その他の機能" aria-label="Permalink to &quot;その他の機能&quot;">​</a></h2><ul><li>グローバル検索：特定のコンテンツを迅速に検索してジャンプできます。</li><li>画像ホスティング管理：画像リポジトリのコンテンツを便利に管理できます。</li><li>テーマと外観：ダークテーマをサポートし、Markdown、コードなどの外観設定をサポートします。</li><li>国際化サポート：現在、中国語と英語に対応しています。</li></ul><h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><h3 id="ダウンロード" tabindex="-1">ダウンロード <a class="header-anchor" href="#ダウンロード" aria-label="Permalink to &quot;ダウンロード&quot;">​</a></h3><p>現在、Mac、Windows、Linuxをサポートしています。Tauri2のクロスプラットフォーム機能のおかげで、将来的にはiOSとAndroidもサポートします。</p><p><a href="https://github.com/codexu/note-gen/releases" target="_blank" rel="noreferrer">NoteGenをダウンロード（アルファ版）</a></p><h3 id="強化" tabindex="-1">強化 <a class="header-anchor" href="#強化" aria-label="Permalink to &quot;強化&quot;">​</a></h3><p>ノートアプリケーションは設定なしで直接使用できます。より良い体験をしたい場合は、設定ページを開いてAIと同期を設定してください。</p><h2 id="コミュニティ" tabindex="-1">コミュニティ <a class="header-anchor" href="#コミュニティ" aria-label="Permalink to &quot;コミュニティ&quot;">​</a></h2><p>NoteGenコミュニティグループに参加して、質問をしたり、使用体験を共有したり、改善提案をしたりできます。また、Tauriについて学び、私と一緒に議論することもできます。</p><p><a href="https://github.com/codexu/note-gen/discussions/110" target="_blank" rel="noreferrer">ディスカッショングループ</a>に参加するためのQRコードをスキャンしてください。QRコードが期限切れの場合は、WeChat xu461229187を追加してグループに参加してください。</p><h2 id="貢献" tabindex="-1">貢献 <a class="header-anchor" href="#貢献" aria-label="Permalink to &quot;貢献&quot;">​</a></h2><ul><li><a href="https://github.com/codexu/note-gen/issues/46" target="_blank" rel="noreferrer">更新計画</a></li><li><a href="https://github.com/codexu/note-gen/issues" target="_blank" rel="noreferrer">バグや改善提案を提出する</a></li><li><a href="https://github.com/codexu/note-gen/discussions" target="_blank" rel="noreferrer">ディスカッション</a></li></ul><h2 id="star-history" tabindex="-1">Star History <a class="header-anchor" href="#star-history" aria-label="Permalink to &quot;Star History&quot;">​</a></h2><p><a href="https://www.star-history.com/#codexu/note-gen&amp;Date" target="_blank" rel="noreferrer"><img src="https://api.star-history.com/svg?repos=codexu/note-gen&amp;type=Date" alt="Star History Chart"></a></p>',40)]))}const g=a(i,[["render",l]]);export{p as __pageData,g as default};
